export default {
  "context-window": {
    "en-us": "The maximum amount of text (measured in tokens) that a language model can process in a single interaction. Think of it as the model's working memory - everything in the context window is available for the model to reference when generating a response.",
    "el": "Η μέγιστη ποσότητα κειμένου (μετρούμενη σε tokens) που μπορεί να επεξεργαστεί ένα γλωσσικό μοντέλο σε μία αλληλεπίδραση. Σκέψου το σαν τη μνήμη εργασίας του μοντέλου · ό,τι βρίσκεται στο context window είναι διαθέσιμο για αναφορά κατά τη δημιουργία απάντησης.",
    "tr": "Bir dil modelinin tek bir etkileşimde işleyebileceği maksimum metin miktarı (token olarak ölçülür). Bunu modelin çalışma belleği olarak düşün · bağlam penceresindeki her şey, model yanıt oluştururken referans alınabilir."
  },
  "rag": {
    "en-us": "Retrieval-Augmented Generation - A technique that enhances language models by retrieving relevant information from external sources before generating a response. RAG combines the knowledge stored in the model with fresh, specific data from databases or documents.",
    "el": "Retrieval-Augmented Generation · Μια τεχνική που ενισχύει τα γλωσσικά μοντέλα ανακτώντας σχετικές πληροφορίες από εξωτερικές πηγές πριν δημιουργήσει απάντηση. Το RAG συνδυάζει τη γνώση που είναι αποθηκευμένη στο μοντέλο με φρέσκα, συγκεκριμένα δεδομένα από βάσεις δεδομένων ή έγγραφα.",
    "tr": "Retrieval-Augmented Generation · Bir yanıt oluşturmadan önce harici kaynaklardan ilgili bilgileri alarak dil modellerini geliştiren bir teknik. RAG, modelde depolanan bilgiyi veritabanları veya belgelerden gelen taze, spesifik verilerle birleştirir."
  },
  "encryption": {
    "en-us": "The process of converting readable data into coded form to prevent unauthorized access. Modern encryption uses mathematical algorithms to scramble data so that only those with the correct key can decrypt and read it.",
    "el": "Η διαδικασία μετατροπής αναγνώσιμων δεδομένων σε κωδικοποιημένη μορφή για την αποτροπή μη εξουσιοδοτημένης πρόσβασης. Η σύγχρονη κρυπτογράφηση χρησιμοποιεί μαθηματικούς αλγόριθμους για να κωδικοποιεί δεδομένα έτσι ώστε μόνο όσοι έχουν το σωστό κλειδί να μπορούν να τα αποκρυπτογραφήσουν και να τα διαβάσουν.",
    "tr": "Yetkisiz erişimi önlemek için okunabilir verileri kodlu forma dönüştürme işlemi. Modern şifreleme, yalnızca doğru anahtara sahip olanların şifresini çözüp okuyabilmesi için verileri karıştırmak amacıyla matematiksel algoritmalar kullanır."
  },
  "firewall": {
    "en-us": "A network security system that monitors and controls incoming and outgoing network traffic based on predetermined security rules. Firewalls act as a barrier between trusted internal networks and untrusted external networks.",
    "el": "Ένα σύστημα ασφάλειας δικτύου που παρακολουθεί και ελέγχει την εισερχόμενη και εξερχόμενη κίνηση δικτύου βάσει προκαθορισμένων κανόνων ασφαλείας. Τα firewalls λειτουργούν ως φράγμα μεταξύ αξιόπιστων εσωτερικών δικτύων και μη αξιόπιστων εξωτερικών δικτύων.",
    "tr": "Önceden belirlenmiş güvenlik kurallarına dayalı olarak gelen ve giden ağ trafiğini izleyen ve kontrol eden bir ağ güvenlik sistemi. Güvenlik duvarları, güvenilir iç ağlar ile güvenilmez dış ağlar arasında bir bariyer görevi görür."
  },
  "malware": {
    "en-us": "Malicious software designed to damage, disrupt, or gain unauthorized access to computer systems. This includes viruses, worms, trojans, ransomware, spyware, and other harmful programs.",
    "el": "Κακόβουλο λογισμικό σχεδιασμένο να προκαλέσει ζημιά, να διαταράξει ή να αποκτήσει μη εξουσιοδοτημένη πρόσβαση σε υπολογιστικά συστήματα. Αυτό περιλαμβάνει ιούς, worms, trojans, ransomware, spyware και άλλα επιβλαβή προγράμματα.",
    "tr": "Bilgisayar sistemlerine zarar vermek, aksatmak veya yetkisiz erişim sağlamak için tasarlanmış kötü amaçlı yazılım. Buna virüsler, solucanlar, truva atları, fidye yazılımları, casus yazılımlar ve diğer zararlı programlar dahildir."
  },
  "phishing": {
    "en-us": "A cyber attack method where attackers impersonate legitimate organizations to trick individuals into revealing sensitive information such as passwords, credit card numbers, or personal data through fake emails, websites, or messages.",
    "el": "Μια μέθοδος κυβερνοεπίθεσης όπου οι επιτιθέμενοι μιμούνται νόμιμους οργανισμούς για να εξαπατήσουν άτομα ώστε να αποκαλύψουν ευαίσθητες πληροφορίες όπως κωδικούς πρόσβασης, αριθμούς πιστωτικών καρτών ή προσωπικά δεδομένα μέσω ψεύτικων emails, ιστοσελίδων ή μηνυμάτων.",
    "tr": "Saldırganların meşru kuruluşları taklit ederek bireyleri sahte e-postalar, web siteleri veya mesajlar aracılığıyla şifreler, kredi kartı numaraları veya kişisel veriler gibi hassas bilgileri ifşa etmeye kandırdığı bir siber saldırı yöntemi."
  },
  "vpn": {
    "en-us": "Virtual Private Network - A secure connection method that creates an encrypted tunnel between your device and a remote server, hiding your internet activity and location while providing access to resources as if you were on a private network.",
    "el": "Εικονικό Ιδιωτικό Δίκτυο - Μια ασφαλής μέθοδος σύνδεσης που δημιουργεί μια κρυπτογραφημένη σήραγγα μεταξύ της συσκευής σου και ενός απομακρυσμένου διακομιστή, κρύβοντας τη δραστηριότητά σου στο διαδίκτυο και την τοποθεσία σου ενώ παρέχει πρόσβαση σε πόρους σαν να βρισκόσουν σε ιδιωτικό δίκτυο.",
    "tr": "Sanal Özel Ağ - Cihazınız ile uzak bir sunucu arasında şifreli bir tünel oluşturan, internet etkinliğinizi ve konumunuzu gizlerken özel bir ağdaymış gibi kaynaklara erişim sağlayan güvenli bir bağlantı yöntemi."
  },
  "api": {
    "en-us": "Application Programming Interface - A set of protocols, routines, and tools that allow different software applications to communicate with each other. APIs define the methods and data formats that applications can use to request and exchange information.",
    "el": "Διεπαφή Προγραμματισμού Εφαρμογών - Ένα σύνολο πρωτοκόλλων, ρουτινών και εργαλείων που επιτρέπουν σε διαφορετικές εφαρμογές λογισμικού να επικοινωνούν μεταξύ τους. Τα APIs ορίζουν τις μεθόδους και τις μορφές δεδομένων που μπορούν να χρησιμοποιήσουν οι εφαρμογές για να ζητήσουν και να ανταλλάξουν πληροφορίες.",
    "tr": "Uygulama Programlama Arayüzü - Farklı yazılım uygulamalarının birbiriyle iletişim kurmasına olanak tanıyan protokoller, rutinler ve araçlar kümesi. API'ler, uygulamaların bilgi istemek ve değiş tokuş etmek için kullanabileceği yöntemleri ve veri formatlarını tanımlar."
  },
  "oauth": {
    "en-us": "Open Authorization - An open standard authorization framework that enables applications to obtain limited access to user accounts on an HTTP service without exposing user passwords. OAuth 2.0 is the current industry standard.",
    "el": "Ανοιχτή Εξουσιοδότηση - Ένα ανοιχτό πρότυπο πλαίσιο εξουσιοδότησης που επιτρέπει στις εφαρμογές να αποκτήσουν περιορισμένη πρόσβαση σε λογαριασμούς χρηστών σε μια υπηρεσία HTTP χωρίς να εκθέτουν τους κωδικούς πρόσβασης των χρηστών. Το OAuth 2.0 είναι το τρέχον βιομηχανικό πρότυπο.",
    "tr": "Açık Yetkilendirme - Uygulamaların kullanıcı şifrelerini açığa çıkarmadan HTTP hizmetindeki kullanıcı hesaplarına sınırlı erişim elde etmesini sağlayan açık standart yetkilendirme çerçevesi. OAuth 2.0 mevcut endüstri standardıdır."
  },
  "jwt": {
    "en-us": "JSON Web Token - A compact, URL-safe token format used to securely transmit information between parties as a JSON object. JWTs are digitally signed and can be verified and trusted, commonly used for authentication and authorization.",
    "el": "JSON Web Token - Μια συμπαγής, ασφαλής για URL μορφή token που χρησιμοποιείται για την ασφαλή μετάδοση πληροφοριών μεταξύ μερών ως JSON αντικείμενο. Τα JWTs είναι ψηφιακά υπογεγραμμένα και μπορούν να επαληθευτούν και να είναι αξιόπιστα, συνήθως χρησιμοποιούνται για έλεγχο ταυτότητας και εξουσιοδότηση.",
    "tr": "JSON Web Token - Taraflar arasında bilgiyi JSON nesnesi olarak güvenli bir şekilde iletmek için kullanılan kompakt, URL-güvenli token formatı. JWT'ler dijital olarak imzalanır ve doğrulanabilir ve güvenilir olup, genellikle kimlik doğrulama ve yetkilendirme için kullanılır."
  },
  "sql-injection": {
    "en-us": "A code injection attack where malicious SQL statements are inserted into application entry points to manipulate database queries. This can lead to unauthorized access to sensitive data, data corruption, or complete database compromise.",
    "el": "Μια επίθεση έγχυσης κώδικα όπου κακόβουλες SQL δηλώσεις εισάγονται σε σημεία εισόδου εφαρμογών για να χειραγωγήσουν τα ερωτήματα βάσης δεδομένων. Αυτό μπορεί να οδηγήσει σε μη εξουσιοδοτημένη πρόσβαση σε ευαίσθητα δεδομένα, καταστροφή δεδομένων ή πλήρη συμβιβασμό της βάσης δεδομένων.",
    "tr": "Veritabanı sorgularını manipüle etmek için kötü amaçlı SQL ifadelerinin uygulama giriş noktalarına eklenmesi yoluyla gerçekleştirilen kod enjeksiyon saldırısı. Bu, hassas verilere yetkisiz erişim, veri bozulması veya tam veritabanı güvenliğinin ele geçirilmesine yol açabilir."
  },
  "two-factor-authentication": {
    "en-us": "A security method that requires users to provide two different authentication factors to verify their identity. Typically combines something you know (password) with something you have (phone, hardware token) or something you are (biometric).",
    "el": "Μια μέθοδος ασφαλείας που απαιτεί από τους χρήστες να παρέχουν δύο διαφορετικούς παράγοντες επαλήθευσης για να επιβεβαιώσουν την ταυτότητά τους. Συνήθως συνδυάζει κάτι που ξέρεις (κωδικός πρόσβασης) με κάτι που έχεις (τηλέφωνο, hardware token) ή κάτι που είσαι (βιομετρικά).",
    "tr": "Kullanıcıların kimliklerini doğrulamak için iki farklı kimlik doğrulama faktörü sağlamalarını gerektiren güvenlik yöntemi. Genellikle bildiğiniz bir şeyi (şifre) sahip olduğunuz bir şeyle (telefon, donanım token) veya olduğunuz bir şeyle (biyometrik) birleştirir."
  },
  "rate-limiting": {
    "en-us": "A technique used to control the amount of incoming and outgoing traffic to or from a network or service. It prevents abuse by limiting the number of requests a user can make within a specific time period, protecting against denial-of-service attacks.",
    "el": "Μια τεχνική που χρησιμοποιείται για τον έλεγχο της ποσότητας εισερχόμενης και εξερχόμενης κίνησης προς ή από ένα δίκτυο ή υπηρεσία. Αποτρέπει την κατάχρηση περιορίζοντας τον αριθμό των αιτημάτων που μπορεί να κάνει ένας χρήστης σε συγκεκριμένο χρονικό διάστημα, προστατεύοντας από επιθέσεις άρνησης υπηρεσίας.",
    "tr": "Bir ağa veya hizmete gelen ve giden trafik miktarını kontrol etmek için kullanılan teknik. Bir kullanıcının belirli bir zaman dilimi içinde yapabileceği istek sayısını sınırlayarak kötüye kullanımı önler ve hizmet reddi saldırılarına karşı koruma sağlar."
  },
  "git-bisect": {
    "en-us": "A Git command that uses binary search to help find the commit that introduced a bug. It automatically checks out commits between a known good and bad state, allowing developers to test and identify the problematic change efficiently.",
    "el": "Μια εντολή Git που χρησιμοποιεί δυαδική αναζήτηση για να βοηθήσει στην εύρεση του commit που εισήγαγε ένα σφάλμα. Αυτόματα κάνει checkout commits μεταξύ μιας γνωστής καλής και κακής κατάστασης, επιτρέποντας στους προγραμματιστές να δοκιμάσουν και να εντοπίσουν την προβληματική αλλαγή αποτελεσματικά.",
    "tr": "Bir hatayı tanıtan commit'i bulmaya yardımcı olmak için ikili arama kullanan Git komutu. Bilinen iyi ve kötü durum arasındaki commit'leri otomatik olarak checkout eder, geliştiricilerin problemli değişikliği verimli bir şekilde test etmelerine ve tanımlamalarına olanak tanır."
  },
  "domain-driven-design": {
    "en-us": "A software development approach that focuses on modeling software around the business domain and its logic. DDD emphasizes collaboration between technical and domain experts to create a shared understanding and ubiquitous language.",
    "el": "Μια προσέγγιση ανάπτυξης λογισμικού που εστιάζει στη μοντελοποίηση λογισμικού γύρω από τον επιχειρηματικό τομέα και τη λογική του. Το DDD δίνει έμφαση στη συνεργασία μεταξύ τεχνικών και εμπειρογνωμόνων τομέα για τη δημιουργία κοινής κατανόησης και παντού παρούσας γλώσσας.",
    "tr": "Yazılımı işletme alanı ve mantığı etrafında modellemeye odaklanan bir yazılım geliştirme yaklaşımı. DDD, ortak bir anlayış ve her yerde geçerli dil oluşturmak için teknik ve alan uzmanları arasındaki işbirliğini vurgular."
  },
  "test-driven-development": {
    "en-us": "A software development methodology where tests are written before the code that implements the functionality. The TDD cycle follows Red-Green-Refactor: write a failing test, make it pass with minimal code, then refactor for quality.",
    "el": "Μια μεθοδολογία ανάπτυξης λογισμικού όπου τα tests γράφονται πριν από τον κώδικα που υλοποιεί τη λειτουργικότητα. Ο κύκλος TDD ακολουθεί το Red-Green-Refactor: γράψε ένα αποτυχημένο test, κάνε το να περάσει με ελάχιστο κώδικα, μετά refactor για ποιότητα.",
    "tr": "İşlevselliği uygulayan koddan önce testlerin yazıldığı bir yazılım geliştirme metodolojisi. TDD döngüsü Kırmızı-Yeşil-Yeniden Düzenle'yi takip eder: başarısız bir test yaz, minimal kodla geçir, sonra kalite için yeniden düzenle."
  },
  "language-server-protocol": {
    "en-us": "A protocol that defines the communication between development tools and language servers. LSP provides features like autocompletion, error highlighting, and go-to-definition across different editors and programming languages.",
    "el": "Ένα πρωτόκολλο που ορίζει την επικοινωνία μεταξύ εργαλείων ανάπτυξης και διακομιστών γλωσσών. Το LSP παρέχει χαρακτηριστικά όπως αυτόματη συμπλήρωση, επισήμανση σφαλμάτων και μετάβαση σε ορισμό σε διαφορετικούς editors και γλώσσες προγραμματισμού.",
    "tr": "Geliştirme araçları ve dil sunucuları arasındaki iletişimi tanımlayan bir protokol. LSP, farklı editörler ve programlama dilleri arasında otomatik tamamlama, hata vurgulama ve tanıma gitme gibi özellikler sağlar."
  },
  "model-context-protocol": {
    "en-us": "A standardized protocol that enables AI models to securely connect to external data sources and tools. MCP allows models to access real-time information, databases, and services while maintaining security and user control.",
    "el": "Ένα τυποποιημένο πρωτόκολλο που επιτρέπει στα μοντέλα AI να συνδέονται με ασφάλεια σε εξωτερικές πηγές δεδομένων και εργαλεία. Το MCP επιτρέπει στα μοντέλα να έχουν πρόσβαση σε πληροφορίες πραγματικού χρόνου, βάσεις δεδομένων και υπηρεσίες διατηρώντας την ασφάλεια και τον έλεγχο χρήστη.",
    "tr": "AI modellerinin harici veri kaynaklarına ve araçlara güvenli bir şekilde bağlanmasını sağlayan standartlaştırılmış protokol. MCP, modellerin güvenlik ve kullanıcı kontrolünü korurken gerçek zamanlı bilgilere, veritabanlarına ve hizmetlere erişmesine olanak tanır."
  },
  "saml": {
    "en-us": "Security Assertion Markup Language - An XML-based standard for exchanging authentication and authorization data between identity providers and service providers. SAML enables single sign-on (SSO) across multiple applications.",
    "el": "Security Assertion Markup Language - Ένα XML-based πρότυπο για την ανταλλαγή δεδομένων επαλήθευσης και εξουσιοδότησης μεταξύ παρόχων ταυτότητας και παρόχων υπηρεσιών. Το SAML επιτρέπει τη μοναδική σύνδεση (SSO) σε πολλαπλές εφαρμογές.",
    "tr": "Güvenlik Onaylama İşaretleme Dili - Kimlik sağlayıcılar ve hizmet sağlayıcılar arasında kimlik doğrulama ve yetkilendirme verilerini değiş tokuş etmek için XML tabanlı standart. SAML, birden fazla uygulama arasında tek oturum açma (SSO) sağlar."
  },
  "scim": {
    "en-us": "System for Cross-domain Identity Management - A standard for automating the exchange of user identity information between identity domains. SCIM simplifies user provisioning and management across different systems and applications.",
    "el": "Σύστημα για Διαχείριση Ταυτότητας Διαφορετικών Τομέων - Ένα πρότυπο για την αυτοματοποίηση της ανταλλαγής πληροφοριών ταυτότητας χρήστη μεταξύ τομέων ταυτότητας. Το SCIM απλοποιεί την παροχή και διαχείριση χρηστών σε διαφορετικά συστήματα και εφαρμογές.",
    "tr": "Etki Alanları Arası Kimlik Yönetimi Sistemi - Kimlik alanları arasında kullanıcı kimlik bilgilerinin değişimini otomatikleştirmek için bir standart. SCIM, farklı sistemler ve uygulamalar arasında kullanıcı sağlama ve yönetimini basitleştirir."
  },
  "openapi": {
    "en-us": "A specification for describing REST APIs that allows both humans and computers to understand service capabilities without accessing source code. OpenAPI enables automatic documentation generation, client SDK creation, and API testing tools.",
    "el": "Μια προδιαγραφή για την περιγραφή REST APIs που επιτρέπει τόσο στους ανθρώπους όσο και στους υπολογιστές να κατανοούν τις δυνατότητες υπηρεσιών χωρίς πρόσβαση στον πηγαίο κώδικα. Το OpenAPI επιτρέπει την αυτόματη δημιουργία τεκμηρίωσης, δημιουργία client SDKs και εργαλεία δοκιμής API.",
    "tr": "İnsanların ve bilgisayarların kaynak koduna erişmeden hizmet yeteneklerini anlamasına olanak tanıyan REST API'lerini tanımlamak için bir spesifikasyon. OpenAPI, otomatik dokümantasyon oluşturma, istemci SDK oluşturma ve API test araçlarını mümkün kılar."
  },
  "git-worktree": {
    "en-us": "A Git feature that allows you to check out multiple branches simultaneously by creating additional working directories. Each worktree maintains its own working directory and index, enabling parallel development without constant branch switching.",
    "el": "Ένα χαρακτηριστικό του Git που σας επιτρέπει να κάνετε checkout πολλαπλά branches ταυτόχρονα δημιουργώντας επιπλέον directories εργασίας. Κάθε worktree διατηρεί το δικό του directory εργασίας και index, επιτρέποντας παράλληλη ανάπτυξη χωρίς συνεχή αλλαγή branch.",
    "tr": "Ek çalışma dizinleri oluşturarak aynı anda birden fazla dalı checkout etmenize olanak tanıyan bir Git özelliği. Her worktree kendi çalışma dizinini ve indeksini korur, sürekli dal değiştirme olmadan paralel geliştirme sağlar."
  },
  "squash-merge": {
    "en-us": "A Git merge strategy that combines all commits from a feature branch into a single commit before merging to the target branch. This creates a cleaner, linear history while preserving the logical grouping of changes.",
    "el": "Μια στρατηγική merge του Git που συνδυάζει όλα τα commits από ένα feature branch σε ένα μόνο commit πριν το merge στο target branch. Αυτό δημιουργεί ένα πιο καθαρό, γραμμικό ιστορικό διατηρώντας τη λογική ομαδοποίηση των αλλαγών.",
    "tr": "Bir özellik dalındaki tüm commit'leri hedef dala birleştirmeden önce tek bir commit'e birleştiren Git birleştirme stratejisi. Bu, değişikliklerin mantıksal gruplandırmasını korurken daha temiz, doğrusal bir geçmiş oluşturur."
  },
  "linear-history": {
    "en-us": "A Git repository history structure where commits form a straight line without merge commits or branching complexity. Linear history is easier to read, debug, and reason about, making it preferred for many development workflows.",
    "el": "Μια δομή ιστορικού αποθετηρίου Git όπου τα commits σχηματίζουν μια ευθεία γραμμή χωρίς merge commits ή πολυπλοκότητα branching. Το γραμμικό ιστορικό είναι πιο εύκολο να διαβαστεί, να γίνει debug και να κατανοηθεί, καθιστώντας το προτιμητέο για πολλές ροές εργασίας ανάπτυξης.",
    "tr": "Commit'lerin birleştirme commit'leri veya dallanma karmaşıklığı olmadan düz bir çizgi oluşturduğu Git depo geçmişi yapısı. Doğrusal geçmiş okumak, hata ayıklamak ve anlamak daha kolaydır, bu da onu birçok geliştirme iş akışı için tercih edilen hale getirir."
  },
  "microservices": {
    "en-us": "An architectural pattern where applications are built as a collection of small, independent services that communicate over well-defined APIs. Each microservice can be developed, deployed, and scaled independently.",
    "el": "Ένα αρχιτεκτονικό πρότυπο όπου οι εφαρμογές κατασκευάζονται ως συλλογή μικρών, ανεξάρτητων υπηρεσιών που επικοινωνούν μέσω καλώς ορισμένων APIs. Κάθε microservice μπορεί να αναπτυχθεί, να αναπτυχθεί και να κλιμακωθεί ανεξάρτητα.",
    "tr": "Uygulamaların iyi tanımlanmış API'ler üzerinden iletişim kuran küçük, bağımsız hizmetler koleksiyonu olarak oluşturulduğu mimari desen. Her mikrohizmet bağımsız olarak geliştirilebilir, dağıtılabilir ve ölçeklendirilebilir."
  },
  "monorepo": {
    "en-us": "A software development strategy where code for multiple projects or components is stored in a single repository. Monorepos enable shared tooling, easier refactoring across projects, and simplified dependency management.",
    "el": "Μια στρατηγική ανάπτυξης λογισμικού όπου ο κώδικας για πολλαπλά projects ή components αποθηκεύεται σε ένα μόνο repository. Τα monorepos επιτρέπουν κοινόχρηστα εργαλεία, ευκολότερο refactoring σε projects και απλοποιημένη διαχείριση dependencies.",
    "tr": "Birden fazla proje veya bileşen için kodun tek bir depoda saklandığı yazılım geliştirme stratejisi. Monorepo'lar paylaşılan araçlar, projeler arası daha kolay yeniden düzenleme ve basitleştirilmiş bağımlılık yönetimi sağlar."
  },
  "infrastructure-as-code": {
    "en-us": "The practice of managing and provisioning computing infrastructure through machine-readable definition files, rather than manual hardware configuration. IaC enables version control, automation, and reproducible deployments of infrastructure.",
    "el": "Η πρακτική διαχείρισης και παροχής υπολογιστικής υποδομής μέσω αρχείων ορισμού αναγνώσιμων από μηχανή, αντί για χειροκίνητη διαμόρφωση hardware. Το IaC επιτρέπει έλεγχο έκδοσης, αυτοματοποίηση και αναπαραγώγιμες αναπτύξεις υποδομής.",
    "tr": "Bilgi işlem altyapısını manuel donanım yapılandırması yerine makine tarafından okunabilir tanım dosyaları aracılığıyla yönetme ve sağlama uygulaması. IaC, sürüm kontrolü, otomasyon ve altyapının tekrarlanabilir dağıtımlarını mümkün kılar."
  },
  "dns-poisoning": {
    "en-us": "A cyber attack that corrupts DNS cache data, causing DNS resolvers to return incorrect IP addresses. Attackers inject forged DNS responses to redirect users to malicious websites or block access to legitimate ones.",
    "el": "Μια κυβερνοεπίθεση που διαφθείρει τα δεδομένα της DNS cache, αναγκάζοντας τους DNS resolvers να επιστρέφουν λανθασμένες διευθύνσεις IP. Οι επιτιθέμενοι εισάγουν πλαστές DNS απαντήσεις για να ανακατευθύνουν χρήστες σε κακόβουλες ιστοσελίδες ή να μπλοκάρουν την πρόσβαση σε νόμιμες.",
    "tr": "DNS önbellek verilerini bozan ve DNS çözümleyicilerinin yanlış IP adresleri döndürmesine neden olan bir siber saldırı. Saldırganlar, kullanıcıları kötü amaçlı web sitelerine yönlendirmek veya meşru sitelere erişimi engellemek için sahte DNS yanıtları enjekte eder."
  },
  "deep-packet-inspection": {
    "en-us": "A network analysis technique that examines the full content of data packets as they pass through a checkpoint. DPI can filter, monitor, and block traffic based on packet contents, commonly used for censorship, security, and traffic management.",
    "el": "Μια τεχνική ανάλυσης δικτύου που εξετάζει το πλήρες περιεχόμενο των πακέτων δεδομένων καθώς περνούν από ένα σημείο ελέγχου. Το DPI μπορεί να φιλτράρει, να παρακολουθεί και να μπλοκάρει κίνηση βάσει του περιεχομένου των πακέτων, χρησιμοποιείται συνήθως για λογοκρισία, ασφάλεια και διαχείριση κίνησης.",
    "tr": "Veri paketlerinin bir kontrol noktasından geçerken tam içeriğini inceleyen bir ağ analizi tekniği. DPI, paket içeriğine göre trafiği filtreleyebilir, izleyebilir ve engelleyebilir; genellikle sansür, güvenlik ve trafik yönetimi için kullanılır."
  },
  "buffer-over-read": {
    "en-us": "A memory safety vulnerability where a program reads data beyond the boundaries of an allocated buffer. This can leak sensitive information from adjacent memory, as seen in Heartbleed and Wallbleed vulnerabilities.",
    "el": "Μια ευπάθεια ασφάλειας μνήμης όπου ένα πρόγραμμα διαβάζει δεδομένα πέρα από τα όρια ενός εκχωρημένου buffer. Αυτό μπορεί να διαρρεύσει ευαίσθητες πληροφορίες από γειτονική μνήμη, όπως φάνηκε στις ευπάθειες Heartbleed και Wallbleed.",
    "tr": "Bir programın tahsis edilmiş bir arabelleğin sınırlarının ötesinde veri okuduğu bir bellek güvenliği açığı. Bu, Heartbleed ve Wallbleed güvenlik açıklarında görüldüğü gibi, komşu bellekten hassas bilgilerin sızmasına neden olabilir."
  },
  "data-exfiltration": {
    "en-us": "The unauthorized transfer of data from a computer or network. Attackers use various techniques to steal sensitive information, including exploiting vulnerabilities, malware, or social engineering to extract data without detection.",
    "el": "Η μη εξουσιοδοτημένη μεταφορά δεδομένων από υπολογιστή ή δίκτυο. Οι επιτιθέμενοι χρησιμοποιούν διάφορες τεχνικές για να κλέψουν ευαίσθητες πληροφορίες, συμπεριλαμβανομένης της εκμετάλλευσης ευπαθειών, malware ή κοινωνικής μηχανικής για εξαγωγή δεδομένων χωρίς ανίχνευση.",
    "tr": "Verilerin bir bilgisayar veya ağdan yetkisiz olarak aktarılması. Saldırganlar, güvenlik açıklarını, kötü amaçlı yazılımları veya sosyal mühendisliği kullanarak hassas bilgileri tespit edilmeden çalmak için çeşitli teknikler kullanır."
  },
  "aslr": {
    "en-us": "Address Space Layout Randomization - A security technique that randomizes the memory addresses used by system and application processes. ASLR makes it harder for attackers to predict target addresses for exploitation.",
    "el": "Address Space Layout Randomization - Μια τεχνική ασφαλείας που τυχαιοποιεί τις διευθύνσεις μνήμης που χρησιμοποιούνται από διεργασίες συστήματος και εφαρμογών. Το ASLR δυσκολεύει τους επιτιθέμενους να προβλέψουν διευθύνσεις-στόχους για εκμετάλλευση.",
    "tr": "Adres Alanı Düzeni Rastgeleleştirme - Sistem ve uygulama süreçleri tarafından kullanılan bellek adreslerini rastgeleleştiren bir güvenlik tekniği. ASLR, saldırganların istismar için hedef adresleri tahmin etmesini zorlaştırır."
  },
  "side-channel": {
    "en-us": "An attack that exploits information gained from the physical implementation of a system rather than weaknesses in the algorithm itself. Side channels include timing information, power consumption, electromagnetic leaks, or even sound.",
    "el": "Μια επίθεση που εκμεταλλεύεται πληροφορίες που αποκτώνται από τη φυσική υλοποίηση ενός συστήματος αντί για αδυναμίες στον ίδιο τον αλγόριθμο. Τα side channels περιλαμβάνουν πληροφορίες χρονισμού, κατανάλωση ενέργειας, ηλεκτρομαγνητικές διαρροές ή ακόμα και ήχο.",
    "tr": "Algoritmanın kendisindeki zayıflıklar yerine bir sistemin fiziksel uygulamasından elde edilen bilgileri kullanan bir saldırı. Yan kanallar zamanlama bilgisi, güç tüketimi, elektromanyetik sızıntılar veya hatta sesi içerir."
  },
  "osint": {
    "en-us": "Open Source Intelligence - The collection and analysis of publicly available information from sources like websites, social media, public records, and news. OSINT is used in security research, investigations, and threat intelligence.",
    "el": "Open Source Intelligence - Η συλλογή και ανάλυση δημόσια διαθέσιμων πληροφοριών από πηγές όπως ιστοσελίδες, κοινωνικά δίκτυα, δημόσια αρχεία και ειδήσεις. Το OSINT χρησιμοποιείται στην έρευνα ασφαλείας, τις έρευνες και την πληροφορία απειλών.",
    "tr": "Açık Kaynak İstihbaratı - Web siteleri, sosyal medya, kamu kayıtları ve haberler gibi kaynaklardan kamuya açık bilgilerin toplanması ve analizi. OSINT, güvenlik araştırması, soruşturmalar ve tehdit istihbaratında kullanılır."
  },
  "ai-agent": {
    "en-us": "An autonomous AI system that can execute tasks, make decisions, and take actions across multiple systems without constant human intervention. Agents use language models to understand goals and interact with tools, APIs, and data sources to accomplish work.",
    "el": "Ένα αυτόνομο σύστημα AI που μπορεί να εκτελεί εργασίες, να παίρνει αποφάσεις και να ενεργεί σε πολλαπλά συστήματα χωρίς συνεχή ανθρώπινη παρέμβαση. Οι agents χρησιμοποιούν γλωσσικά μοντέλα για να κατανοούν στόχους και να αλληλεπιδρούν με εργαλεία, APIs και πηγές δεδομένων για να ολοκληρώνουν δουλειά.",
    "tr": "Sürekli insan müdahalesi olmadan birden fazla sistem genelinde görevleri yürütebilen, kararlar alabilen ve eylemler gerçekleştirebilen otonom bir AI sistemi. Ajanlar, hedefleri anlamak ve işleri tamamlamak için araçlar, API'ler ve veri kaynaklarıyla etkileşim kurmak üzere dil modellerini kullanır."
  },
  "systems-of-record": {
    "en-us": "Enterprise software applications that serve as the authoritative source of truth for specific business data. Examples include CRMs for customer data, ERPs for financial data, and HRIS for employee information. These systems capture what happened but often miss why decisions were made.",
    "el": "Εφαρμογές εταιρικού λογισμικού που λειτουργούν ως η επίσημη πηγή αλήθειας για συγκεκριμένα επιχειρηματικά δεδομένα. Παραδείγματα περιλαμβάνουν CRMs για δεδομένα πελατών, ERPs για οικονομικά δεδομένα και HRIS για πληροφορίες εργαζομένων. Αυτά τα συστήματα καταγράφουν τι συνέβη αλλά συχνά χάνουν το γιατί πάρθηκαν αποφάσεις.",
    "tr": "Belirli iş verileri için yetkili gerçeklik kaynağı olarak hizmet veren kurumsal yazılım uygulamaları. Örnekler arasında müşteri verileri için CRM'ler, finansal veriler için ERP'ler ve çalışan bilgileri için HRIS bulunur. Bu sistemler ne olduğunu kaydeder ancak genellikle kararların neden verildiğini kaçırır."
  },
  "crm": {
    "en-us": "Customer Relationship Management - Software that manages a company's interactions with customers and prospects. CRMs track sales pipelines, customer communications, deal stages, and revenue data, serving as the system of record for customer information.",
    "el": "Customer Relationship Management - Λογισμικό που διαχειρίζεται τις αλληλεπιδράσεις μιας εταιρείας με πελάτες και υποψήφιους πελάτες. Τα CRMs παρακολουθούν pipelines πωλήσεων, επικοινωνίες πελατών, στάδια συμφωνιών και δεδομένα εσόδων, λειτουργώντας ως σύστημα καταγραφής για πληροφορίες πελατών.",
    "tr": "Müşteri İlişkileri Yönetimi - Bir şirketin müşteriler ve potansiyel müşterilerle etkileşimlerini yöneten yazılım. CRM'ler satış hatlarını, müşteri iletişimlerini, anlaşma aşamalarını ve gelir verilerini izler, müşteri bilgileri için kayıt sistemi olarak hizmet eder."
  },
  "knowledge-graph": {
    "en-us": "A structured representation of knowledge using entities and their relationships, typically stored as a graph database. Knowledge graphs help AI systems understand connections between concepts, but they require predefined schemas unlike context graphs which emerge from agent execution traces.",
    "el": "Μια δομημένη αναπαράσταση γνώσης χρησιμοποιώντας οντότητες και τις σχέσεις τους, συνήθως αποθηκευμένη ως graph database. Τα knowledge graphs βοηθούν τα συστήματα AI να κατανοούν συνδέσεις μεταξύ εννοιών, αλλά απαιτούν προκαθορισμένα schemas σε αντίθεση με τα context graphs που προκύπτουν από ίχνη εκτέλεσης agents.",
    "tr": "Varlıkları ve ilişkilerini kullanarak genellikle grafik veritabanı olarak depolanan yapılandırılmış bilgi temsili. Bilgi grafikleri, AI sistemlerinin kavramlar arasındaki bağlantıları anlamasına yardımcı olur, ancak ajan yürütme izlerinden ortaya çıkan bağlam grafiklerinin aksine önceden tanımlanmış şemalar gerektirir."
  },
  "decision-trace": {
    "en-us": "A record of why a specific decision was made, including the context, inputs considered, exceptions granted, approvals obtained, and precedents followed. Decision traces capture the reasoning behind actions, not just the final outcome, and form the building blocks of context graphs.",
    "el": "Μια καταγραφή του γιατί πάρθηκε μια συγκεκριμένη απόφαση, συμπεριλαμβανομένου του πλαισίου, των εισόδων που εξετάστηκαν, των εξαιρέσεων που χορηγήθηκαν, των εγκρίσεων που ελήφθησαν και των προηγουμένων που ακολουθήθηκαν. Τα decision traces καταγράφουν τη σκέψη πίσω από ενέργειες, όχι μόνο το τελικό αποτέλεσμα, και αποτελούν τα δομικά στοιχεία των context graphs.",
    "tr": "Bağlam, değerlendirilen girdiler, verilen istisnalar, alınan onaylar ve takip edilen emsaller dahil olmak üzere belirli bir kararın neden verildiğinin kaydı. Karar izleri, yalnızca nihai sonucu değil, eylemlerin arkasındaki mantığı yakalar ve bağlam grafiklerinin yapı taşlarını oluşturur."
  },
  "context-graph": {
    "en-us": "A living record of decision traces stitched across entities over time, capturing not just what happened but why it happened. Context graphs make decision lineage queryable, turning exceptions into precedent and enabling AI agents to understand how organizations actually operate beyond formal policies.",
    "el": "Μια ζωντανή καταγραφή decision traces συνδεδεμένων σε οντότητες με το χρόνο, καταγράφοντας όχι μόνο τι συνέβη αλλά γιατί συνέβη. Τα context graphs κάνουν τη γενεαλογία αποφάσεων αναζητήσιμη, μετατρέποντας εξαιρέσεις σε προηγούμενα και επιτρέποντας στους AI agents να κατανοούν πώς οι οργανισμοί λειτουργούν πραγματικά πέρα από τις επίσημες πολιτικές.",
    "tr": "Yalnızca ne olduğunu değil, neden olduğunu da yakalayarak zaman içinde varlıklar arasında birleştirilen karar izlerinin canlı kaydı. Bağlam grafikleri, karar soyunu sorgulanabilir hale getirir, istisnaları emsale dönüştürür ve AI ajanlarının kuruluşların resmi politikaların ötesinde gerçekte nasıl çalıştığını anlamasını sağlar."
  },
  "auto-regressive-model": {
    "en-us": "A type of language model that generates text by predicting the next token based on all previous tokens in the sequence. Auto-regressive models like GPT and Claude process input sequentially, using the entire context history to inform each prediction.",
    "el": "Ένας τύπος γλωσσικού μοντέλου που δημιουργεί κείμενο προβλέποντας το επόμενο token με βάση όλα τα προηγούμενα tokens στην ακολουθία. Τα auto-regressive μοντέλα όπως το GPT και το Claude επεξεργάζονται το input διαδοχικά, χρησιμοποιώντας ολόκληρο το ιστορικό του context για να ενημερώσουν κάθε πρόβλεψη.",
    "tr": "Dizideki tüm önceki tokenlara dayanarak sonraki tokeni tahmin ederek metin üreten bir dil modeli türü. GPT ve Claude gibi oto-regresif modeller, her tahmini bilgilendirmek için tüm bağlam geçmişini kullanarak girdiyi sırayla işler."
  },
  "kv-cache": {
    "en-us": "Key-Value cache · A memory optimization technique in transformer models that stores previously computed attention key and value matrices. KV cache enables faster inference by avoiding redundant computations, but becomes a memory bandwidth bottleneck as context windows grow.",
    "el": "Key-Value cache · Μια τεχνική βελτιστοποίησης μνήμης σε transformer μοντέλα που αποθηκεύει προηγουμένως υπολογισμένες attention key και value matrices. Το KV cache επιτρέπει ταχύτερη inference αποφεύγοντας περιττούς υπολογισμούς, αλλά γίνεται bottleneck εύρους ζώνης μνήμης καθώς τα context windows μεγαλώνουν.",
    "tr": "Anahtar-Değer önbelleği · Daha önce hesaplanmış dikkat anahtarı ve değer matrislerini depolayan transformer modellerinde bellek optimizasyon tekniği. KV önbelleği, gereksiz hesaplamaları önleyerek daha hızlı çıkarım sağlar, ancak bağlam pencereleri büyüdükçe bellek bant genişliği darboğazı haline gelir."
  },
  "mcp": {
    "en-us": "Model Context Protocol · An open standard by Anthropic that enables AI applications to securely connect to external data sources and tools. MCP provides a standardized way for AI models to access databases, APIs, and local resources through server implementations.",
    "el": "Model Context Protocol · Ένα ανοιχτό πρότυπο από την Anthropic που επιτρέπει στις AI εφαρμογές να συνδέονται με ασφάλεια σε εξωτερικές πηγές δεδομένων και εργαλεία. Το MCP παρέχει έναν τυποποιημένο τρόπο για τα AI μοντέλα να έχουν πρόσβαση σε βάσεις δεδομένων, APIs και τοπικούς πόρους μέσω υλοποιήσεων διακομιστή.",
    "tr": "Model Bağlam Protokolü · AI uygulamalarının harici veri kaynaklarına ve araçlarına güvenli bir şekilde bağlanmasını sağlayan Anthropic tarafından geliştirilen açık standart. MCP, AI modellerinin sunucu uygulamaları aracılığıyla veritabanlarına, API'lere ve yerel kaynaklara erişmesi için standartlaştırılmış bir yol sağlar."
  },
  "speculative-execution": {
    "en-us": "A technique where a processor or system pre-executes future operations before knowing they are needed, then discards results if the prediction was wrong. Speculative execution trades occasional wasted work for reduced average latency, and is the foundation of both CPU branch prediction and LLM speculative decoding.",
    "el": "Μια τεχνική όπου ένας επεξεργαστής ή σύστημα προ-εκτελεί μελλοντικές λειτουργίες πριν ξέρει αν χρειάζονται, και απορρίπτει τα αποτελέσματα αν η πρόβλεψη ήταν λάθος. Ανταλλάσσει περιστασιακή σπαταλημένη εργασία με μειωμένη μέση καθυστέρηση.",
    "tr": "Bir işlemcinin veya sistemin gelecekteki işlemleri gerekip gerekmediğini bilmeden önceden yürüttüğü ve tahmin yanlışsa sonuçları attığı bir teknik. Spekülatif yürütme, zaman zaman yapılan gereksiz işlerle ortalama gecikmeyi azaltmayı dengeler."
  },
  "react-loop": {
    "en-us": "The canonical Thought → Action → Observation loop used by tool-using LLM agents, formalized in the ReAct paper (ICLR 2023). Each reasoning step produces a tool call, which produces an observation that feeds the next reasoning step — creating a strictly sequential dependency chain that is the primary latency bottleneck in multi-step agents.",
    "el": "Ο κανονικός βρόχος Thought → Action → Observation που χρησιμοποιείται από LLM agents με εργαλεία, τυποποιημένος στο paper ReAct (ICLR 2023). Κάθε βήμα συλλογισμού παράγει μια κλήση εργαλείου, η οποία παράγει μια παρατήρηση που τροφοδοτεί το επόμενο βήμα — δημιουργώντας αυστηρά διαδοχικές εξαρτήσεις.",
    "tr": "ReAct makalesinde (ICLR 2023) resmileştirilen, araç kullanan LLM ajanları tarafından kullanılan kanonik Düşünce → Eylem → Gözlem döngüsü. Her akıl yürütme adımı bir araç çağrısı üretir ve bu da bir sonraki adımı besleyen bir gözlem üretir — çok adımlı ajanlarda temel gecikme darboğazını oluşturur."
  },
  "branch-prediction": {
    "en-us": "A CPU optimization that guesses which path a conditional branch will take before the branch condition is evaluated. Modern processors achieve 95–99% prediction accuracy, allowing them to pre-execute instructions and avoid costly pipeline stalls when the guess is correct.",
    "el": "Μια βελτιστοποίηση CPU που μαντεύει ποιο μονοπάτι θα ακολουθήσει μια υπό συνθήκη διακλάδωση πριν αξιολογηθεί η συνθήκη. Οι σύγχρονοι επεξεργαστές επιτυγχάνουν ακρίβεια πρόβλεψης 95–99%, αποφεύγοντας δαπανηρές στάσεις pipeline.",
    "tr": "Dal koşulu değerlendirilmeden önce koşullu dalın hangi yolu izleyeceğini tahmin eden bir CPU optimizasyonu. Modern işlemciler %95–99 tahmin doğruluğuna ulaşarak, tahmin doğru olduğunda maliyetli ardışık düzen durmalarından kaçınır."
  },
  "transactional-memory": {
    "en-us": "A CPU mechanism that allows concurrent read operations to proceed optimistically without locking, committing writes atomically only after validating no conflicts occurred. Hardware transactional memory (HTM), as in Intel's TSX extensions, applies this read/write asymmetry at the hardware level — the same asymmetry exploited by speculative agent action frameworks.",
    "el": "Ένας μηχανισμός CPU που επιτρέπει σε ταυτόχρονες λειτουργίες ανάγνωσης να προχωρούν αισιόδοξα χωρίς κλείδωμα, δεσμεύοντας εγγραφές ατομικά μόνο αφού επαληθευτεί ότι δεν υπήρξαν συγκρούσεις. Υλοποιήσεις όπως το Intel TSX εφαρμόζουν αυτή την ασυμμετρία ανάγνωσης/εγγραφής σε επίπεδο hardware.",
    "tr": "Eşzamanlı okuma işlemlerinin kilitleme olmadan iyimser bir şekilde ilerlemesine izin veren, yazmaları yalnızca çakışma olmadığını doğruladıktan sonra atomik olarak işleyen bir CPU mekanizması. Intel TSX gibi donanım işlemsel bellek uygulamaları bu okuma/yazma asimetrisini donanım düzeyinde uygular."
  },
  "drum-memory": {
    "en-us": "A type of computer storage used in 1950s–60s machines where data was recorded on a rotating magnetic cylinder. Programs ran by reading instructions off the drum as it spun, making the physical placement of code critical to performance — a well-placed program could run 50x faster than a naively arranged one.",
    "el": "Ένας τύπος αποθήκευσης υπολογιστή που χρησιμοποιήθηκε σε μηχανές της δεκαετίας 1950–60, όπου τα δεδομένα καταγράφονταν σε περιστρεφόμενο μαγνητικό κύλινδρο. Τα προγράμματα εκτελούνταν διαβάζοντας εντολές από τον τύμπανο καθώς περιστρεφόταν, καθιστώντας την τοποθέτηση του κώδικα κρίσιμη για τις επιδόσεις.",
    "tr": "1950'ler–60'larda kullanılan ve verilerin dönen manyetik bir silindire kaydedildiği bilgisayar depolama türü. Programlar, dönerken davuldan talimatları okuyarak çalışırdı; bu da kodun fiziksel yerleşimini performans için kritik kılardı — iyi yerleştirilmiş bir program, rastgele düzenlenmiş birinden 50 kat daha hızlı çalışabilirdi."
  },
  "self-modifying-code": {
    "en-us": "Programs that alter their own instructions while running. Standard practice on early computers where loops were implemented by writing a new address directly into an instruction word — there was no other way to iterate over memory. On modern hardware, self-modifying code is rare and generally discouraged.",
    "el": "Προγράμματα που τροποποιούν τις δικές τους εντολές ενώ εκτελούνται. Ήταν καθιερωμένη πρακτική στους πρώτους υπολογιστές, όπου οι βρόχοι υλοποιούνταν γράφοντας μια νέα διεύθυνση απευθείας μέσα σε μια λέξη εντολής — δεν υπήρχε άλλος τρόπος επανάληψης.",
    "tr": "Çalışırken kendi talimatlarını değiştiren programlar. Döngülerin bir talimat sözcüğüne doğrudan yeni bir adres yazılarak uygulandığı erken bilgisayarlarda standart bir uygulamaydı — bellekte yinelemenin başka yolu yoktu. Modern donanımda öz-değiştiren kod nadirdir ve genellikle önerilmez."
  },
  "posix-spawn": {
    "en-us": "A POSIX standard function for spawning child processes that performs several setup steps — changing the working directory, configuring file descriptors, adjusting resource limits — before executing the target binary via execve. Because these setup steps happen first, an EACCES error from posix_spawn may not indicate a problem with the target binary itself.",
    "el": "Μια τυπική συνάρτηση POSIX για τη δημιουργία θυγατρικών διεργασιών που εκτελεί αρκετά βήματα ρύθμισης — αλλαγή working directory, ρύθμιση file descriptors, προσαρμογή resource limits — πριν εκτελέσει το target binary μέσω execve. Επειδή αυτά τα βήματα γίνονται πρώτα, ένα σφάλμα EACCES από το posix_spawn μπορεί να μη σημαίνει πρόβλημα με το ίδιο το binary.",
    "tr": "execve aracılığıyla hedef ikiliyi çalıştırmadan önce çeşitli kurulum adımları gerçekleştiren — çalışma dizinini değiştirme, dosya tanımlayıcılarını yapılandırma, kaynak sınırlarını ayarlama — alt süreçler oluşturmak için POSIX standart fonksiyonu. Bu kurulum adımları önce gerçekleştiğinden, posix_spawn'dan gelen bir EACCES hatası hedef ikili dosyanın kendisinde bir sorun olduğunu göstermeyebilir."
  },
  "dac": {
    "en-us": "Discretionary Access Control — the standard Unix file permission model where access is determined by file ownership and permission bits (read, write, execute) for the owner, group, and others. DAC is called 'discretionary' because file owners can grant access to others at their own discretion.",
    "el": "Discretionary Access Control — το τυπικό μοντέλο δικαιωμάτων αρχείων Unix, όπου η πρόσβαση καθορίζεται από την ιδιοκτησία αρχείου και τα permission bits (read, write, execute) για τον ιδιοκτήτη, την ομάδα και τους υπόλοιπους. Ονομάζεται 'discretionary' επειδή οι ιδιοκτήτες αρχείων μπορούν να παραχωρήσουν πρόσβαση σε άλλους κατά την κρίση τους.",
    "tr": "İsteğe Bağlı Erişim Kontrolü — erişimin dosya sahipliği ve sahip, grup ve diğerleri için izin bitleri (okuma, yazma, çalıştırma) tarafından belirlendiği standart Unix dosya izin modeli. Dosya sahipleri kendi takdirlerine göre başkalarına erişim verebildiğinden 'isteğe bağlı' olarak adlandırılır."
  },
  "mac": {
    "en-us": "Mandatory Access Control — a security model where access decisions are enforced by the operating system based on policies set by an administrator, not by individual resource owners. Unlike DAC, users and processes cannot override MAC rules even if they own the resource. SELinux and AppArmor are MAC implementations on Linux.",
    "el": "Mandatory Access Control — ένα μοντέλο ασφαλείας όπου οι αποφάσεις πρόσβασης επιβάλλονται από το λειτουργικό σύστημα βάσει πολιτικών που ορίζει ο διαχειριστής, όχι από τους ιδιοκτήτες πόρων. Σε αντίθεση με το DAC, οι χρήστες και οι διεργασίες δεν μπορούν να παρακάμψουν τους κανόνες MAC ακόμα και αν κατέχουν τον πόρο. Το SELinux και το AppArmor είναι υλοποιήσεις MAC στο Linux.",
    "tr": "Zorunlu Erişim Kontrolü — erişim kararlarının bireysel kaynak sahipleri tarafından değil, bir yönetici tarafından belirlenen politikalara dayanarak işletim sistemi tarafından uygulandığı güvenlik modeli. DAC'ın aksine, kullanıcılar ve işlemler kaynağa sahip olsalar bile MAC kurallarını geçersiz kılamazlar. SELinux ve AppArmor, Linux'ta MAC uygulamalarıdır."
  },
  "selinux": {
    "en-us": "Security-Enhanced Linux — a mandatory access control (MAC) system built into the Linux kernel that enforces fine-grained security policies independent of file ownership. SELinux assigns security labels (contexts) to every process and file, and policy rules determine which labels can interact. Violations appear in the audit log, not as standard permission errors.",
    "el": "Security-Enhanced Linux — ένα σύστημα mandatory access control (MAC) ενσωματωμένο στον πυρήνα Linux που επιβάλλει λεπτομερείς πολιτικές ασφαλείας ανεξάρτητα από την ιδιοκτησία αρχείων. Το SELinux αναθέτει security labels (contexts) σε κάθε διεργασία και αρχείο, και οι κανόνες πολιτικής καθορίζουν ποια labels μπορούν να αλληλεπιδράσουν. Οι παραβιάσεις εμφανίζονται στο audit log, όχι ως τυπικά σφάλματα δικαιωμάτων.",
    "tr": "Güvenlik Artırılmış Linux — dosya sahipliğinden bağımsız olarak ayrıntılı güvenlik politikaları uygulayan Linux çekirdeğine yerleşik bir zorunlu erişim kontrolü (MAC) sistemi. SELinux her sürece ve dosyaya güvenlik etiketleri (bağlamlar) atar ve hangi etiketlerin etkileşime girebileceğini politika kuralları belirler. İhlaller standart izin hataları olarak değil, denetim günlüğünde görünür."
  },
  "mcs-label": {
    "en-us": "Multi-Category Security label — a SELinux feature that assigns one or more category tags to a process or file, allowing fine-grained isolation beyond basic user/role/type enforcement. Podman uses MCS labels to isolate container volumes: the :Z option assigns an exclusive MCS category so that only a specific container can access that volume.",
    "el": "Multi-Category Security label — ένα χαρακτηριστικό SELinux που αναθέτει μία ή περισσότερες κατηγορίες σε μια διεργασία ή αρχείο, επιτρέποντας λεπτομερή απομόνωση πέρα από την βασική επιβολή user/role/type. Το Podman χρησιμοποιεί MCS labels για να απομονώσει container volumes: η επιλογή :Z αναθέτει μια αποκλειστική MCS κατηγορία ώστε μόνο ένα συγκεκριμένο container να έχει πρόσβαση σε αυτό το volume.",
    "tr": "Çok Kategorili Güvenlik etiketi — temel kullanıcı/rol/tür uygulamasının ötesinde ayrıntılı izolasyona olanak tanıyarak bir sürece veya dosyaya bir veya daha fazla kategori etiketi atayan SELinux özelliği. Podman, kapsayıcı birimlerini izole etmek için MCS etiketlerini kullanır: :Z seçeneği, yalnızca belirli bir kapsayıcının bu birime erişebilmesi için özel bir MCS kategorisi atar."
  },
  "user-namespace": {
    "en-us": "A Linux kernel feature that maps a range of user and group IDs inside a container to a different range on the host. User namespaces enable rootless containers — a process inside the container can appear to run as uid 0 (root) while being an unprivileged user on the host. The mapping also means host files appear with different ownership inside the container unless uid alignment is configured explicitly.",
    "el": "Ένα χαρακτηριστικό του πυρήνα Linux που αντιστοιχίζει ένα εύρος user και group IDs μέσα σε ένα container σε ένα διαφορετικό εύρος στον host. Τα user namespaces επιτρέπουν rootless containers — μια διεργασία μέσα στο container μπορεί να φαίνεται ότι εκτελείται ως uid 0 (root) ενώ είναι μη προνομιούχος χρήστης στον host. Η αντιστοίχιση σημαίνει επίσης ότι τα αρχεία του host εμφανίζονται με διαφορετική ιδιοκτησία μέσα στο container εκτός αν η ευθυγράμμιση uid ρυθμιστεί ρητά.",
    "tr": "Bir kapsayıcı içindeki kullanıcı ve grup kimliklerinin bir aralığını konaktaki farklı bir aralıkla eşleyen Linux çekirdeği özelliği. Kullanıcı ad alanları kök olmayan kapsayıcıları etkinleştirir — kapsayıcı içindeki bir işlem, konakta ayrıcalıksız bir kullanıcı olurken uid 0 (root) olarak çalışıyor gibi görünebilir. Eşleme aynı zamanda, uid hizalaması açıkça yapılandırılmadığı sürece konak dosyalarının kapsayıcı içinde farklı sahiplikle göründüğü anlamına gelir."
  },
  "seccomp": {
    "en-us": "Secure Computing mode — a Linux kernel feature that restricts which system calls a process is allowed to make. Container runtimes apply seccomp profiles to limit the attack surface of containers. If a seccomp profile blocks a syscall like execve or fork, the process cannot spawn children — but the parent process itself would also fail to start, making seccomp easy to rule out when the parent is already running.",
    "el": "Secure Computing mode — ένα χαρακτηριστικό του πυρήνα Linux που περιορίζει ποιες κλήσεις συστήματος μπορεί να κάνει μια διεργασία. Τα container runtimes εφαρμόζουν seccomp profiles για να περιορίσουν την επιφάνεια επίθεσης των containers. Αν ένα seccomp profile μπλοκάρει μια syscall όπως execve ή fork, η διεργασία δεν μπορεί να δημιουργήσει θυγατρικές — αλλά και η γονική διεργασία δεν θα μπορούσε να εκκινήσει, κάνοντας το seccomp εύκολο να αποκλειστεί όταν ο γονέας ήδη τρέχει.",
    "tr": "Güvenli Bilgi İşlem modu — bir işlemin hangi sistem çağrılarını yapmasına izin verildiğini kısıtlayan Linux çekirdeği özelliği. Kapsayıcı çalışma zamanları, kapsayıcıların saldırı yüzeyini sınırlamak için seccomp profilleri uygular. Bir seccomp profili execve veya fork gibi bir sistem çağrısını engellerse, işlem alt süreçler oluşturamaz — ancak ana işlem de başlatılamaz, bu da ana işlem zaten çalışırken seccomp'u dışlamayı kolaylaştırır."
  },
  "instruction-word": {
    "en-us": "A fixed-width binary value that encodes a single CPU operation. An instruction word packs the operation type (opcode), the memory address to act on, and modifier bits into one integer the processor decodes and executes. On early computers, instruction words and data words were the same size and lived in the same memory, making it possible to treat code as data.",
    "el": "Μια δυαδική τιμή σταθερού πλάτους που κωδικοποιεί μία μόνο λειτουργία CPU. Μια λέξη εντολής συμπτύσσει τον τύπο λειτουργίας (opcode), τη διεύθυνση μνήμης και bits τροποποιητή σε έναν ακέραιο που αποκωδικοποιεί και εκτελεί ο επεξεργαστής.",
    "tr": "Tek bir CPU işlemini kodlayan sabit genişlikli ikili değer. Bir talimat sözcüğü, işlemcinin çözümleyip yürüttüğü bir tam sayıya işlem türünü (işlem kodu), üzerinde çalışılacak bellek adresini ve değiştirici bitleri sıkıştırır."
  },
  "opcode": {
    "en-us": "The part of an instruction word that tells the processor which operation to perform — add, load, jump, compare, and so on. Opcodes are decoded by the CPU's control unit before the instruction executes. On early fixed-width instruction machines, arithmetic overflow could in principle corrupt the opcode field and change what an instruction meant.",
    "el": "Το τμήμα μιας λέξης εντολής που λέει στον επεξεργαστή ποια λειτουργία να εκτελέσει — πρόσθεση, φόρτωση, άλμα, σύγκριση κ.λπ. Οι opcodes αποκωδικοποιούνται από τη μονάδα ελέγχου της CPU πριν εκτελεστεί η εντολή.",
    "tr": "İşlemciye hangi işlemi yapacağını söyleyen talimat sözcüğünün parçası — toplama, yükleme, atlama, karşılaştırma vb. İşlem kodları, talimat yürütülmeden önce CPU'nun kontrol birimi tarafından çözümlenir."
  }
};
